def merge_sorted(a: List[Int], b: List[Int]) -> List[Int]:
    var r = List[Int]()
    var i = 0
    var j = 0
    while i < len(a) and j < len(b):
        if a[i] <= b[j]: r.append(a[i])
        else: r.append(b[j])
        i += 1
        j += 1
    while i < len(a): r.append(a[i])
